+        if (msg is null) return Task.CompletedTask;
+
+        var idx = _messages.IndexOf(msg);
+        var reactions = msg.Reactions.ToList();
+        var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);
+        if (existing is not null)
+        {
+            if (!existing.Users.Contains("You"))
+            {
+                reactions.Remove(existing);
+                reactions.Add(existing with { Users = [..existing.Users, "You"] });
+            }
+        }
+        else
+        {
+            reactions.Add(new Reaction(emoji, ["You"]));
+        }
+        _messages[idx] = msg with { Reactions = reactions };
