@namespace sv_49c19e92a4fd4c7abfee24a9239acb65.Components.Chat

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="badge bg-danger rounded-pill">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-desc text-muted">@TruncatedDescription</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;

    private async Task HandleClick() => await OnSelected.InvokeAsync(Channel.Id);
}

@namespace sv_49c19e92a4fd4c7abfee24a9239acb65.Components.Chat

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button type="button" class="emoji-btn" @onclick="() => SelectEmoji(emoji)" title="@emoji">
            @emoji
        </button>
    }
</div>

@code {
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    private async Task SelectEmoji(string emoji) => await OnEmojiSelected.InvokeAsync(emoji);
}

@namespace sv_49c19e92a4fd4c7abfee24a9239acb65.Components.Chat

<div class="message-input-area">
    <textarea class="form-control" rows="2" placeholder="@Placeholder"
              @bind="_text" @bind:event="oninput"
              @onkeydown="HandleKeyDown"></textarea>
    <button class="btn btn-primary mt-2" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(_text)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string _text = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(_text)) return;
        var content = _text.Trim();
        _text = "";
        await OnSend.InvokeAsync(content);
    }
}

@namespace sv_49c19e92a4fd4c7abfee24a9239acb65.Components.Chat

<div class="message-bubble @(_showActions ? "hovered" : "")"
     @onmouseenter="() => _showActions = true"
     @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <strong class="message-author">@Message.Author</strong>
        <span class="message-time text-muted">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-bar">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button type="button" class="btn btn-link btn-sm thread-link p-0" @onclick="HandleReplyClick">
            💬 @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button type="button" class="btn btn-outline-secondary btn-sm" @onclick="HandleReplyClick" title="Reply in thread">
                💬 Reply
            </button>
            <button type="button" class="btn btn-outline-secondary btn-sm" @onclick="ToggleEmojiPicker" title="Add reaction">
                😊 React
            </button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <EmojiPicker OnEmojiSelected="HandleReaction" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void OnMouseLeave()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private async Task HandleReplyClick() => await OnReplyClicked.InvokeAsync(Message.Id);

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleReaction(string emoji)
    {
        _showEmojiPicker = false;
        _showActions = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

