@page "/chat"
@using sv_49c19e92a4fd4c7abfee24a9239acb65.Components.Chat
@using sv_49c19e92a4fd4c7abfee24a9239acb65.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_activeChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="area-header">
                <h5 class="m-0"># @_activeChannel.Name</h5>
                <span class="text-muted">@_activeChannel.Description</span>
            </div>

            <div class="message-list">
                @if (_hasMoreMessages)
                {
                    <div class="text-center py-2">
                        <button class="btn btn-link btn-sm" @onclick="LoadOlderMessages" disabled="@_loadingMore">
                            @(_loadingMore ? "Loading…" : "⬆ Load older messages")
                        </button>
                    </div>
                }

                @foreach (var msg in _messages)
                {
                    <MessageBubble Message="msg"
                                   ReplyCount="GetReplyCount(msg.Id)"
                                   OnReplyClicked="OpenThread"
                                   OnReactionAdded="AddReaction" />
                }

                @if (_messages.Count == 0 && !_loading)
                {
                    <div class="text-center text-muted py-5">No messages yet. Start the conversation!</div>
                }
            </div>

            <div class="area-input">
                <MessageInput Placeholder="@($"Message #{_activeChannel.Name}")"
                              ButtonText="Send"
                              OnSend="SendMessage" />
            </div>
        }
        else
        {
            <div class="d-flex align-items-center justify-content-center h-100 text-muted">
                <div class="text-center">
                    <h4>💬</h4>
                    <p>Select a channel to start chatting</p>
                </div>
            </div>
        }
    </div>

    @if (_threadOpen)
    {
        <ThreadPanel RootMessage="_threadRoot"
                     Replies="_threadReplies"
                     OnClose="CloseThread"
                     OnReplySend="SendThreadReply"
                     OnReactionAdded="AddReaction" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _replyCounts = new();
    private bool _loading;
    private bool _loadingMore;
    private bool _hasMoreMessages;
    private const int PageSize = 20;

    // Thread state
    private bool _threadOpen;
    private int? _threadRootId;
    private Message? _threadRoot;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _loading = true;

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _hasMoreMessages = _messages.Count >= PageSize;
        await BuildReplyCounts();
        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync(); // Refresh unread counts
        _loading = false;

        CloseThread();
    }

    private async Task LoadOlderMessages()
    {
        if (_activeChannelId is null) return;
        _loadingMore = true;

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
        _hasMoreMessages = older.Count >= PageSize;
        _messages.InsertRange(0, older);
        await BuildReplyCounts();
        _loadingMore = false;
    }

    private async Task BuildReplyCounts()
    {
        _replyCounts.Clear();
        foreach (var msg in _messages)
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            var count = thread.Count(t => t.ReplyToId == msg.Id);
            if (count > 0) _replyCounts[msg.Id] = count;
        }
    }

    private int GetReplyCount(int messageId) =>
        _replyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task SendMessage(string content)
    {
        if (_activeChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, content, null);
        _messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootId = messageId;
        var thread = await ChatService.GetThreadAsync(messageId);
        _threadRoot = thread.FirstOrDefault();
        _threadReplies = thread.Skip(1).ToList();
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootId = null;
        _threadRoot = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeChannelId is null || _threadRootId is null) return;
        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, content, _threadRootId);
        _threadReplies.Add(msg);
        // Update reply count in main view
        _replyCounts[_threadRootId.Value] = _threadReplies.Count;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        // Refresh messages to show updated reactions
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messages.Count);
        }
        // Refresh thread if open
        if (_threadOpen && _threadRootId is not null)
        {
            var thread = await ChatService.GetThreadAsync(_threadRootId.Value);
            _threadRoot = thread.FirstOrDefault();
            _threadReplies = thread.Skip(1).ToList();
        }
    }
}

/* ===== Chat Layout ===== */
.chat-layout {
    display: flex;
    height: calc(100vh - 3.5rem);
    margin: -1rem -2rem -1rem -2rem;
    overflow: hidden;
}

/* ===== Channel Sidebar ===== */
::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2b2d42;
    color: #edf2f4;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #1a1b2e;
}

::deep .sidebar-header {
    padding: 1rem;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
    flex-shrink: 0;
}

::deep .channel-list {
    overflow-y: auto;
    flex: 1;
}

::deep .channel-item {
    padding: 0.6rem 1rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background-color 0.15s;
}

::deep .channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

::deep .channel-item.active {
    background: rgba(255, 255, 255, 0.12);
    border-left-color: #8338ec;
}

::deep .channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .channel-desc {
    font-size: 0.75rem;
    opacity: 0.6;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ===== Message Area ===== */
.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    transition: width 0.2s ease;
}

.message-area.expanded {
    width: 80%;
}

::deep .area-header {
    padding: 0.75rem 1.25rem;
    border-bottom: 1px solid #e9ecef;
    flex-shrink: 0;
    background: #fafbfc;
}

::deep .area-header h5 {
    font-size: 1.1rem;
}

::deep .area-header .text-muted {
    font-size: 0.8rem;
}

::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 1rem 1.25rem;
}

::deep .area-input {
    border-top: 1px solid #e9ecef;
    padding: 0.75rem 1.25rem;
    flex-shrink: 0;
    background: #fafbfc;
}

/* ===== Message Bubble ===== */
::deep .message-bubble {
    padding: 0.5rem 0.75rem;
    border-radius: 6px;
    margin-bottom: 0.25rem;
    position: relative;
    transition: background-color 0.1s;
}

::deep .message-bubble.hovered,
::deep .message-bubble:hover {
    background: #f0f2f5;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

::deep .message-author {
    font-size: 0.9rem;
    color: #2b2d42;
}

::deep .message-time {
    font-size: 0.7rem;
}

::deep .message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    color: #333;
}

/* ===== Reactions ===== */
::deep .reaction-bar {
    display: flex;
    gap: 0.35rem;
    margin-top: 0.35rem;
    flex-wrap: wrap;
}

::deep .reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
    padding: 0.1rem 0.45rem;
    border-radius: 1rem;
    background: #e8ebf0;
    font-size: 0.8rem;
    cursor: default;
    border: 1px solid #d0d5dd;
}

::deep .thread-link {
    font-size: 0.8rem;
    color: #5b5fc7 !important;
    text-decoration: none !important;
    margin-top: 0.25rem;
}

::deep .thread-link:hover {
    text-decoration: underline !important;
}

/* ===== Message Actions (hover) ===== */
::deep .message-actions {
    position: absolute;
    top: 0.25rem;
    right: 0.5rem;
    display: flex;
    gap: 0.25rem;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 0.15rem 0.25rem;
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.1);
}

::deep .message-actions .btn {
    font-size: 0.75rem;
    padding: 0.15rem 0.4rem;
}

/* ===== Emoji Picker ===== */
::deep .emoji-picker {
    display: flex;
    gap: 0.15rem;
    padding: 0.35rem;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    margin-top: 0.25rem;
    width: fit-content;
}

::deep .emoji-btn {
    background: none;
    border: none;
    font-size: 1.25rem;
    padding: 0.25rem;
    cursor: pointer;
    border-radius: 4px;
    line-height: 1;
    transition: background-color 0.1s;
}

::deep .emoji-btn:hover {
    background: #f0f0f0;
}

/* ===== Thread Panel ===== */
::deep .thread-panel {
    width: 25%;
    min-width: 280px;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #e9ecef;
    background: #fafbfc;
}

::deep .thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e9ecef;
    flex-shrink: 0;
}

::deep .thread-root-quote {
    padding: 0.75rem 1rem;
    background: #eef0f4;
    border-bottom: 1px solid #e0e0e0;
    font-size: 0.85rem;
    flex-shrink: 0;
}

::deep .thread-root-quote p {
    color: #555;
    margin-top: 0.25rem;
}

::deep .thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 0.75rem 1rem;
}

::deep .thread-input {
    border-top: 1px solid #e9ecef;
    padding: 0.75rem 1rem;
    flex-shrink: 0;
}

/* ===== Message Input ===== */
::deep .message-input-area .form-control {
    resize: none;
    border-radius: 8px;
    font-size: 0.9rem;
}

::deep .message-input-area .btn {
    float: right;
    font-size: 0.85rem;
}

