{"file_text": "@page "/chat"
@using sv_49c19e92a4fd4c7abfee24a9239acb65.Components.Chat
@using sv_49c19e92a4fd4c7abfee24a9239acb65.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_activeChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="area-header">
                <h5 class="m-0"># @_activeChannel.Name</h5>
                <span class="text-muted">@_activeChannel.Description</span>
            </div>

            <div class="message-list">
                @if (_hasMoreMessages)
                {
                    <div class="text-center py-2">
                        <button class="btn btn-link btn-sm" @onclick="LoadOlderMessages" disabled="@_loadingMore">
                            @(_loadingMore ? "Loading…" : "⬆ Load older messages")
                        </button>
                    </div>
                }

                @foreach (var msg in _messages)
                {
                    <MessageBubble Message="msg"
                                   ReplyCount="GetReplyCount(msg.Id)"
                                   OnReplyClicked="OpenThread"
                                   OnReactionAdded="AddReaction" />
                }

                @if (_messages.Count == 0 && !_loading)
                {
                    <div class="text-center text-muted py-5">No messages yet. Start the conversation!</div>
                }
            </div>

            <div class="area-input">
                <MessageInput Placeholder="@($"Message #{_activeChannel.Name}")"
                              ButtonText="Send"
                              OnSend="SendMessage" />
            </div>
        }
        else
        {
            <div class="d-flex align-items-center justify-content-center h-100 text-muted">
                <div class="text-center">
                    <h4>💬</h4>
                    <p>Select a channel to start chatting</p>
                </div>
            </div>
        }
    </div>

    @if (_threadOpen)
    {
        <ThreadPanel RootMessage="_threadRoot"
                     Replies="_threadReplies"
                     OnClose="CloseThread"
                     OnReplySend="SendThreadReply"
                     OnReactionAdded="AddReaction" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _replyCounts = new();
    private bool _loading;
    private bool _loadingMore;
    private bool _hasMoreMessages;
    private const int PageSize = 20;

    // Thread state
    private bool _threadOpen;
    private int? _threadRootId;
    private Message? _threadRoot;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _loading = true;

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _hasMoreMessages = _messages.Count >= PageSize;
        await BuildReplyCounts();
        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync(); // Refresh unread counts
        _loading = false;

        CloseThread();
    }

    private async Task LoadOlderMessages()
    {
        if (_activeChannelId is null) return;
        _loadingMore = true;

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
        _hasMoreMessages = older.Count >= PageSize;
        _messages.InsertRange(0, older);
        await BuildReplyCounts();
        _loadingMore = false;
    }

    private async Task BuildReplyCounts()
    {
        _replyCounts.Clear();
        foreach (var msg in _messages)
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            var count = thread.Count(t => t.ReplyToId == msg.Id);
            if (count > 0) _replyCounts[msg.Id] = count;
        }
    }

    private int GetReplyCount(int messageId) =>
        _replyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task SendMessage(string content)
    {
        if (_activeChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, content, null);
        _messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootId = messageId;
        var thread = await ChatService.GetThreadAsync(messageId);
        _threadRoot = thread.FirstOrDefault();
        _threadReplies = thread.Skip(1).ToList();
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootId = null;
        _threadRoot = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeChannelId is null || _threadRootId is null) return;
        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, content, _threadRootId);
        _threadReplies.Add(msg);
        // Update reply count in main view
        _replyCounts[_threadRootId.Value] = _threadReplies.Count;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        // Refresh messages to show updated reactions
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messages.Count);
        }
        // Refresh thread if open
        if (_threadOpen && _threadRootId is not null)
        {
            var thread = await ChatService.GetThreadAsync(_threadRootId.Value);
            _threadRoot = thread.FirstOrDefault();
            _threadReplies = thread.Skip(1).ToList();
        }
    }
}
