toolArgs.file_text:
/* ===== Chat Layout ===== */
.chat-layout {
    display: flex;
    height: calc(100vh - 3.5rem);
    margin: -1rem -2rem -1rem -2rem;
    overflow: hidden;
}

/* ===== Channel Sidebar ===== */
::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2b2d42;
    color: #edf2f4;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #1a1b2e;
}

::deep .sidebar-header {
    padding: 1rem;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
    flex-shrink: 0;
}

::deep .channel-list {
    overflow-y: auto;
    flex: 1;
}

::deep .channel-item {
    padding: 0.6rem 1rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background-color 0.15s;
}

::deep .channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

::deep .channel-item.active {
    background: rgba(255, 255, 255, 0.12);
    border-left-color: #8338ec;
}

::deep .channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .channel-desc {
    font-size: 0.75rem;
    opacity: 0.6;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ===== Message Area ===== */
.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    transition: width 0.2s ease;
}

.message-area.expanded {
    width: 80%;
}

::deep .area-header {
    padding: 0.75rem 1.25rem;
    border-bottom: 1px solid #e9ecef;
    flex-shrink: 0;
    background: #fafbfc;
}

::deep .area-header h5 {
    font-size: 1.1rem;
}

::deep .area-header .text-muted {
    font-size: 0.8rem;
}

::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 1rem 1.25rem;
}

::deep .area-input {
    border-top: 1px solid #e9ecef;
    padding: 0.75rem 1.25rem;
    flex-shrink: 0;
    background: #fafbfc;
}

/* ===== Message Bubble ===== */
::deep .message-bubble {
    padding: 0.5rem 0.75rem;
    border-radius: 6px;
    margin-bottom: 0.25rem;
    position: relative;
    transition: background-color 0.1s;
}

::deep .message-bubble.hovered,
::deep .message-bubble:hover {
    background: #f0f2f5;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

::deep .message-author {
    font-size: 0.9rem;
    color: #2b2d42;
}

::deep .message-time {
    font-size: 0.7rem;
}

::deep .message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    color: #333;
}

/* ===== Reactions ===== */
::deep .reaction-bar {
    display: flex;
    gap: 0.35rem;
    margin-top: 0.35rem;
    flex-wrap: wrap;
}

::deep .reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
    padding: 0.1rem 0.45rem;
    border-radius: 1rem;
    background: #e8ebf0;
    font-size: 0.8rem;
    cursor: default;
    border: 1px solid #d0d5dd;
}

::deep .thread-link {
    font-size: 0.8rem;
    color: #5b5fc7 !important;
    text-decoration: none !important;
    margin-top: 0.25rem;
}

::deep .thread-link:hover {
    text-decoration: underline !important;
}

/* ===== Message Actions (hover) ===== */
::deep .message-actions {
    position: absolute;
    top: 0.25rem;
    right: 0.5rem;
    display: flex;
    gap: 0.25rem;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 0.15rem 0.25rem;
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.1);
}

::deep .message-actions .btn {
    font-size: 0.75rem;
    padding: 0.15rem 0.4rem;
}

/* ===== Emoji Picker ===== */
::deep .emoji-picker {
    display: flex;
    gap: 0.15rem;
    padding: 0.35rem;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    margin-top: 0.25rem;
    width: fit-content;
}

::deep .emoji-btn {
    background: none;
    border: none;
    font-size: 1.25rem;
    padding: 0.25rem;
    cursor: pointer;
    border-radius: 4px;
    line-height: 1;
    transition: background-color 0.1s;
}

::deep .emoji-btn:hover {
    background: #f0f0f0;
}

/* ===== Thread Panel ===== */
::deep .thread-panel {
    width: 25%;
    min-width: 280px;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #e9ecef;
    background: #fafbfc;
}

::deep .thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e9ecef;
    flex-shrink: 0;
}

::deep .thread-root-quote {
    padding: 0.75rem 1rem;
    background: #eef0f4;
    border-bottom: 1px solid #e0e0e0;
    font-size: 0.85rem;
    flex-shrink: 0;
}

::deep .thread-root-quote p {
    color: #555;
    margin-top: 0.25rem;
}

::deep .thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 0.75rem 1rem;
}

::deep .thread-input {
    border-top: 1px solid #e9ecef;
    padding: 0.75rem 1rem;
    flex-shrink: 0;
}

/* ===== Message Input ===== */
::deep .message-input-area .form-control {
    resize: none;
    border-radius: 8px;
    font-size: 0.9rem;
}

::deep .message-input-area .btn {
    float: right;
    font-size: 0.85rem;
}

